{"content":"const si = require('systeminformation');

/**
 * System Monitor Service
 * Collects CPU and memory usage stats using systeminformation library
 */
class SystemMonitor {
  constructor() {
    this.lastCpuData = null;
  }

  /**
   * Get current CPU usage (overall + per core)
   * @returns {Promise<Object>} CPU stats
   */
  async getCpuStats() {
    try {
      const currentLoad = await si.currentLoad();

      return {
        overall: parseFloat(currentLoad.currentLoad.toFixed(1)),
        cores: currentLoad.cpus.map(core => parseFloat(core.load.toFixed(1)))
      };
    } catch (error) {
      console.error('Error getting CPU stats:', error);
      return { overall: 0, cores: [] };
    }
  }

  /**
   * Get current memory usage
   * @returns {Promise<Object>} Memory stats
   */
  async getMemoryStats() {
    try {
      const mem = await si.mem();

      const total = mem.total;
      const used = mem.used;
      const free = mem.free;
      const percent = parseFloat(((used / total) * 100).toFixed(1));

      return {
        total,
        used,
        free,
        percent
      };
    } catch (error) {
      console.error('Error getting memory stats:', error);
      return { total: 0, used: 0, free: 0, percent: 0 };
    }
  }

  /**
   * Get combined system stats snapshot
   * @returns {Promise<Object>} Combined CPU + Memory stats
   */
  async getStats() {
    const [cpu, memory] = await Promise.all([
      this.getCpuStats(),
      this.getMemoryStats()
    ]);

    return {
      timestamp: new Date().toISOString(),
      cpu,
      memory
    };
  }
}

module.exports = SystemMonitor;
