{"content":"/* Dark-themed System Monitor Dashboard */

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    background: linear-gradient(135deg, #1a1a2e 0%, #16213e 50%, #0f3460 100%);
    color: #e0e0e0;
    min-height: 100vh;
}

.container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 20px;
}

/* Header */
header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 30px;
    padding: 20px;
    background: rgba(255, 255, 255, 0.05);
    border-radius: 12px;
    backdrop-filter: blur(10px);
    border: 1px solid rgba(255, 255, 255, 0.1);
}

header h1 {
    font-size: 1.8rem;
    font-weight: 600;
    color: #fff;
}

.status {
    display: flex;
    gap: 20px;
    align-items: center;
    font-size: 0.9rem;
}

#connection-status {
    font-weight: 600;
    transition: color 0.3s ease;
}

#connection-status.connected {
    color: #4ade80;
}

#connection-status.disconnected {
    color: #f87171;
}

#last-update {
    color: #94a3b8;
}

/* Stats Grid */
.stats-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(500px, 1fr));
    gap: 20px;
    margin-bottom: 30px;
}

/* Stat Cards */
.stat-card {
    background: rgba(255, 255, 255, 0.05);
    border-radius: 16px;
    padding: 24px;
    backdrop-filter: blur(10px);
    border: 1px solid rgba(255, 255, 255, 0.1);
    transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.stat-card:hover {
    transform: translateY(-2px);
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.3);
}

.stat-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 20px;
}

.stat-header h2 {
    font-size: 1.3rem;
    font-weight: 500;
    color: #fff;
}

.stat-value {
    font-size: 2rem;
    font-weight: 700;
    color: #60a5fa;
}

/* Chart Container */
.chart-container {
    position: relative;
    height: 250px;
    margin-bottom: 20px;
    background: rgba(0, 0, 0, 0.2);
    border-radius: 12px;
    padding: 10px;
}

/* Stat Details */
.stat-details {
    display: flex;
    flex-direction: column;
    gap: 10px;
}

.detail-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 8px 12px;
    background: rgba(255, 255, 255, 0.03);
    border-radius: 8px;
}

.detail-label {
    color: #94a3b8;
    font-size: 0.9rem;
}

.detail-value {
    color: #e0e0e0;
    font-weight: 600;
    font-size: 0.95rem;
}

/* Footer */
footer {
    text-align: center;
    padding: 20px;
    color: #64748b;
    font-size: 0.85rem;
}

/* Responsive */
@media (max-width: 768px) {
    .stats-grid {
        grid-template-columns: 1fr;
    }

    header {
        flex-direction: column;
        gap: 15px;
        text-align: center;
    }

    .stat-header h2 {
        font-size: 1.1rem;
    }

    .stat-value {
        font-size: 1.5rem;
    }
}
