/**
 * Update CPU display
 */
function updateCpuDisplay(stats) {
  const { overall, cores } = stats.cpu;

  cpuPercent.textContent = `${overall}%`;
  cpuOverall.textContent = `${overall}%`;
  cpuCores.textContent = cores.length > 0 
    ? cores.map(c => `${c}%`).join(' | ')
    : '--';

  // Update chart
  const now = new Date();
  const timeLabel = formatTime(now);

  cpuDataBuffer.labels.push(timeLabel);
  cpuDataBuffer.data.push(overall);

  // Keep only last MAX_DATA_POINTS
  if (cpuDataBuffer.labels.length > MAX_DATA_POINTS) {
    cpuDataBuffer.labels.shift();
    cpuDataBuffer.data.shift();
  }

  cpuChart.data.labels = cpuDataBuffer.labels;
  cpuChart.data.datasets[0].data = cpuDataBuffer.data;
  cpuChart.update('none'); // 'none' mode for smooth animation
}

/**
 * Update Memory display
 */
function updateMemoryDisplay(stats) {
  const { total, used, free, percent } = stats.memory;

  memoryPercent.textContent = `${percent}%`;
  memoryUsed.textContent = formatBytes(used);
  memoryFree.textContent = formatBytes(free);
  memoryTotal.textContent = formatBytes(total);

  // Update chart
  const now = new Date();
  const timeLabel = formatTime(now);

  memoryDataBuffer.labels.push(timeLabel);
  memoryDataBuffer.data.push(percent);

  // Keep only last MAX_DATA_POINTS
  if (memoryDataBuffer.labels.length > MAX_DATA_POINTS) {
    memoryDataBuffer.labels.shift();
    memoryDataBuffer.data.shift();
  }

  memoryChart.data.labels = memoryDataBuffer.labels;
  memoryChart.data.datasets[0].data = memoryDataBuffer.data;
  memoryChart.update('none');
