{"content":"const express = require('express');
const http = require('http');
const { Server } = require('socket.io');
const path = require('path');
const SystemMonitor = require('./monitor');

const app = express();
const server = http.createServer(app);
const io = new Server(server, {
  cors: {
    origin: "*",
    methods: ["GET", "POST"]
  }
});

const monitor = new SystemMonitor();
const PORT = process.env.PORT || 3001;
const POLL_INTERVAL = 2000; // 2 seconds

// Serve static files from public directory
app.use(express.static(path.join(__dirname, 'public')));

// REST API endpoint for current stats snapshot
app.get('/api/stats', async (req, res) => {
  try {
    const stats = await monitor.getStats();
    res.json(stats);
  } catch (error) {
    console.error('Error fetching stats:', error);
    res.status(500).json({ error: 'Failed to fetch system stats' });
  }
});

// Health check endpoint
app.get('/api/health', (req, res) => {
  res.json({ status: 'ok', uptime: process.uptime() });
});

// Socket.io connection handling
io.on('connection', (socket) => {
  console.log(`Client connected: ${socket.id}`);

  // Send initial stats to new client
  monitor.getStats().then(stats => {
    socket.emit('stats', stats);
  });

  socket.on('disconnect', () => {
    console.log(`Client disconnected: ${socket.id}`);
  });
});

// Broadcast stats to all connected clients every 2 seconds
async function broadcastStats() {
  try {
    const stats = await monitor.getStats();
    io.emit('stats', stats);
  } catch (error) {
    console.error('Error broadcasting stats:', error);
  }
}

// Start the polling interval
const statsInterval = setInterval(broadcastStats, POLL_INTERVAL);

// Graceful shutdown
process.on('SIGTERM', () => {
  clearInterval(statsInterval);
  server.close(() => {
    console.log('Server closed');
    process.exit(0);
  });
});

process.on('SIGINT', () => {
  clearInterval(statsInterval);
  server.close(() => {
    console.log('Server closed');
    process.exit(0);
  });
});

server.listen(PORT, () => {
  console.log(`🚀 CPU & Memory Monitor running on http://localhost:${PORT}`);
  console.log(`📊 Dashboard: http://localhost:${PORT}`);
  console.log(`📡 API: http://localhost:${PORT}/api/stats`);
});
